import * as React from 'react';
import { styled, alpha } from '@mui/material/styles';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Toolbar from '@mui/material/Toolbar';
import InputBase from '@mui/material/InputBase';
import SearchIcon from '@mui/icons-material/Search';
import Badge from '@mui/material/Badge';
import MailIcon from '@mui/icons-material/Mail';
import ImageField from '../ImageField/ImageField';
import KeyboardArrowDownIcon from '@mui/icons-material/KeyboardArrowDown';
import { IconButton,Typography } from '@mui/material';
import Menu from '@mui/material/Menu';
import MenuItem from '@mui/material/MenuItem';
import ListItemIcon from '@mui/material/ListItemIcon';
import HomeIcon from '@mui/icons-material/Home';
import PersonIcon from '@mui/icons-material/Person';
import CalendarMonthIcon from '@mui/icons-material/CalendarMonth';
import SettingsIcon from '@mui/icons-material/Settings';
import LogoutIcon from '@mui/icons-material/Logout';
import './Appbar.css';
import LabelField from "../../Components/LabelField/LabelField";
import { Link } from 'react-router-dom';

const user= require('../../Images/user-40-2.jpg');
const Search = styled('div')(({ theme }) => ({
  position: 'relative',
  borderRadius: theme.shape.borderRadius,
  backgroundColor: 'Lightgrey',
}));

const SearchIconWrapper = styled('div')(({ theme }) => ({
  padding: theme.spacing(0, 25),
  height: '100%',
  position: 'absolute',
  pointerEvents: 'none',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  color:'black',
  opacity:'.4',
  
}));

const StyledInputBase = styled(InputBase)(({ theme }) => ({
  color: 'black',
  '& .MuiInputBase-input': {
    padding: theme.spacing(1, 1, 1, 0),
    marginLeft: `calc(1em + ${theme.spacing(1)})`,
  },
}));

export default function SearchAppBar() {
  const [anchorEl, setAnchorEl] = React.useState(null);
  const open = Boolean(anchorEl);
  const handleClick = (event) => {
    setAnchorEl(event.currentTarget);
  };
  const handleClose = () => {
    setAnchorEl(null);
  };
  
  return (
    <Box sx={{ flexGrow: 1 }}>
      <AppBar position="fixed" sx={{width:1150,backgroundColor:'rgb(255,255,255)'}}>
        <Toolbar>
          <Search>
            <SearchIconWrapper>
              <SearchIcon />
            </SearchIconWrapper>
            <StyledInputBase
              placeholder="Type to search"
              inputProps={{ 'aria-label': 'search' }}
            />
          </Search>
          <Box sx={{display: 'flex',flexGrow: '2',
              justifyContent: 'flex-end',marginRight:2}}>
            <Badge badgeContent={5} color="error" >
              <MailIcon color="action" />
            </Badge>
          </Box>
          <Box sx={{display: 'flex',
              justifyContent: 'flex-end',margin:0}}>
            <ImageField  image={{src:user}} style={{borderRadius:'50%'}}></ImageField> 
            <IconButton onClick={handleClick} size="small" 
              aria-controls={open ? 'account-menu' : undefined}
              aria-haspopup="true"
              aria-expanded={open ? 'true' : undefined}>
              <KeyboardArrowDownIcon />
            </IconButton>
          </Box>
          <Menu
        anchorEl={anchorEl}
        id="account-menu"
        open={open}
        onClose={handleClose}
        onClick={handleClose}
        PaperProps={{
          elevation: 0,
          sx: {
            overflow: 'visible',
            filter: 'drop-shadow(0px 2px 8px rgba(0,0,0,0.32))',
            mt: 1.5,
            '& .MuiAvatar-root': {
              width: 32,
              height: 32,
              ml: -0.5,
              mr: 1,
            },
            '&:before': {
              content: '""',
              display: 'block',
              position: 'absolute',
              top: 0,
              right: 14,
              width: 10,
              height: 10,
              bgcolor: 'background.paper',
              transform: 'translateY(-50%) rotate(45deg)',
              zIndex: 0,
            },
          },
        }}
        transformOrigin={{ horizontal: 'right', vertical: 'top' }}
        anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
        >
          <MenuItem>
            <Link to='/Pages/edit-account' className='link'>
              <ListItemIcon>
                <HomeIcon fontSize="small" className='icon'/>
              </ListItemIcon>
              <Typography style={{fontSize:14,fontFamily:'Lato,sans-serif'}}>Edit Account</Typography>
            </Link>
          </MenuItem>
          <MenuItem>
          <Link to='/Pages/user-profile' className='link'>
            <ListItemIcon>
              <PersonIcon fontSize="small" className='icon'/>
            </ListItemIcon>
            <Typography style={{fontSize:14,fontFamily:'Lato,sans-serif'}}>User Profile</Typography>
          </Link>
          </MenuItem>
          <MenuItem>
          <Link to='/Pages/calender' className='link'>
            <ListItemIcon>
              <CalendarMonthIcon fontSize="small" className='icon'/>
            </ListItemIcon>
            <Typography style={{fontSize:14,fontFamily:'Lato,sans-serif'}}>Calender</Typography>
          </Link>
          </MenuItem>
          <MenuItem>
          <Link to='/Pages/setting' className='link'>
            <ListItemIcon>
              <SettingsIcon fontSize="small" className='icon'/>
            </ListItemIcon>
            <Typography style={{fontSize:14,fontFamily:'Lato,sans-serif'}}>Setting</Typography>
          </Link>
          </MenuItem>
          <MenuItem>
          <Link to='/Pages/logout' className='link'>
            <ListItemIcon>
              <LogoutIcon fontSize="small" className='icon'/>
            </ListItemIcon>
            <Typography style={{fontSize:14,fontFamily:'Lato,sans-serif'}}>Log Out</Typography>
          </Link>
          </MenuItem>
        </Menu>
        </Toolbar>
      </AppBar>
    </Box>
  );
}