import { FormControlLabel, Switch } from "@mui/material";

export default function SwitchLabelField(props){
    return(
        <div>
            <FormControlLabel
             componentsProps={{ typography: { fontSize: 14 ,fontFamily:"'Lato', sans-serif"} }} 
            control={<Switch defaultChecked />} 
            label={props.label} />
        </div>
    )
}