import * as React from 'react';
import { styled } from '@mui/material/styles';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell, { tableCellClasses } from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import Paper from '@mui/material/Paper';
import { useState } from 'react';
import { useEffect } from 'react';
import ModeEditOutlinedIcon from '@mui/icons-material/ModeEditOutlined';
import { IconButton, Box,Typography } from '@mui/material';
import DeleteForeverOutlinedIcon from '@mui/icons-material/DeleteForeverOutlined';

const StyledTableCell = styled(TableCell)(({ theme }) => ({
  [`&.${tableCellClasses.head}`]: {
    backgroundColor:' rgba(31,32,34,.1)',
    color: 'black',
    fontWeight:700,
  },
  [`&.${tableCellClasses.body}`]: {
    fontSize: 14,
  },
}));

const StyledTableRow = styled(TableRow)(({ theme }) => ({
  '&:nth-of-type(odd)': {
    backgroundColor: theme.palette.action.hover,
  },

  '&:last-child td, &:last-child th': {
    border: 0,
  },
}));

function createData (
  img,
  name, 
  email,
  number, 
  date,
  fromTo,
  doctor,
  injury,
 ) {
  return { img, name, email, number, date,fromTo,doctor,injury };
}


export default function AppointTable() {
    const [appointment,setAppointment]=useState([]);
    

    useEffect(()=>{
        fetch("/json/Appointment.json")
        .then(res=>res.json())
        .then(res=>{
            console.log(res);
            setAppointment(res)
        })
    },[])

  return (
    <TableContainer sx={{marginTop:5}}component={Paper}>
      <Table sx={{ minWidth: 700 }} aria-label="customized table">
        <TableHead>
          <TableRow>
            <StyledTableCell>Photo</StyledTableCell>
            <StyledTableCell align="center">Name</StyledTableCell>
            <StyledTableCell align="center">Email</StyledTableCell>
            <StyledTableCell align="center">Date</StyledTableCell>
            <StyledTableCell align="center">Number</StyledTableCell>
            <StyledTableCell align="center">Visit time</StyledTableCell>
            <StyledTableCell align="center">Doctor</StyledTableCell>
            <StyledTableCell align="center">Injury/Condition</StyledTableCell>
            <StyledTableCell align="center">Actions</StyledTableCell>

          </TableRow>
        </TableHead>
        <TableBody>
          {appointment.map((row) => (
            <StyledTableRow key={row.name}>
              <StyledTableCell component="th" scope="row">
                <img src={row.img} style={{borderRadius:'50%'}}/>
              </StyledTableCell>
              <StyledTableCell align="center">{row.name}</StyledTableCell>
              <StyledTableCell style={{color:"blue"}} align="center">{row.email}</StyledTableCell>
              <StyledTableCell align="center">{row.date}</StyledTableCell>
              <StyledTableCell style={{color:"blue"}} align="center">{row.number}</StyledTableCell>
              <StyledTableCell align="center">{row.fromTo}</StyledTableCell>
              <StyledTableCell align="center">{row.doctor}</StyledTableCell>
              <StyledTableCell align="center">{row.injury}</StyledTableCell>
              <StyledTableCell align="center">
                <Box sx={{display:'flex',alignItems:'flex-start',flexWrap:'nowrap'}}>
                <IconButton sx={{color:'white',borderRadius:'50%',backgroundColor:'blue',margin:'3px'}}><ModeEditOutlinedIcon/></IconButton>
                <IconButton sx={{color:'white',borderRadius:'50%',backgroundColor:'#ed5564',margin:'3px'}}><DeleteForeverOutlinedIcon/></IconButton>
                </Box>
              </StyledTableCell>
            </StyledTableRow>
            
          ))}
        </TableBody>
      </Table>
     
    </TableContainer>
  );
}