import * as React from 'react';
import {   Grid,  Typography } from "@mui/material"
import ImageField from "../../Components/ImageField/ImageField";
import LabelField from "../../Components/LabelField/LabelField";
import SwitchLabelField from "../../Components/SwitchLabelField/SwitchLabelField";
import TextFieldComponent from "../../Components/TextField/TextField";
import { Link } from 'react-router-dom';
import ButtonField from '../../Components/ButtonField/ButtonField';
import { useDispatch, useSelector } from 'react-redux';
import { setPassword, setUsername } from '../../Redux/Action/Actions';
import { useNavigate } from 'react-router-dom';
import {useState} from 'react';

const loginPageImage = require ('../../Images/pageside.jpg');
const logoOfPage = require ('../../Images/logo.png');

export default function SignIn(){
    const dispatch = useDispatch();
    const user=useSelector(state=>state.feature.user);
    const navigate=useNavigate();
  
    const onClickHandler=()=>{
        alert(JSON.stringify(user));
        const options={
            method:'POST',
            headers:new Headers({"Content-type": "application/json"}),
            mode:'cors',
            body:JSON.stringify(user),
        }
        fetch('https://fakestoreapi.com/users',options)
            .then(res=>res.json())
            .then(json=>{
                console.log(json);
                navigate("/Pages/dashboard");

            })
    };
    const onChangeUsername=(e)=>{
        dispatch(
            setUsername(e.target.value)
        )
    };
    const onChangePassword=(e)=>{
        dispatch(
            setPassword(e.target.value)
        )
    };
   

    return(
        <div>
            <Grid container spacing={2}>
                <Grid xs={12} md={4} lg={4} item>
                    <Grid container  spacing={2} padding={5}>
                        <Grid item xs={12} md={12} lg={12} >
                            <ImageField   image={{src:logoOfPage}}></ImageField> 
                        </Grid>
                        <Grid  xs={12} md={12} lg={12} item marginTop={10}>
                            <LabelField style={{fontWeight:"700",fontFamily:"Lato, sans-serif"}} variant={"h5"} label={"Login-form"}/> 
                            <LabelField style={{fontWeight:"400",color:"#8f9091",fontSize:"14px",fontFamily:"Lato, sans-serif"}}variant={"p"} label={"Login to access your Account"}/>
                        
                        </Grid>
                        <Grid item xs={12} md={12} lg={12}>
                            <TextFieldComponent style={{display:"flex",flex:"1 1",
                              marginBottom:"20px",fontSize:"14px",fontFamily:"Lato, sans-serif",borderRadius:"20px",
                              backgroundColor: 'rgba(235,235,235)',color: "#1f2022"}} 
                              size={"small"} placeholder={"Login"} onChange={onChangeUsername} 
                              value={user.username}>
                            </TextFieldComponent>
                       
                            <TextFieldComponent  style={{display:"flex",flex:"1 1",
                              fontSize:"14px",fontFamily:"Lato, sans-serif",borderRadius:"20px",color: "#1f2022",
                              backgroundColor:'rgba(235,235,235)'}}
                              placeholder={"Password"} size={"small"} onChange={onChangePassword}
                              value={user.password}>
                            </TextFieldComponent> 
                        </Grid>
                        <Grid item xs={12} md={12} lg={12}>
                            <SwitchLabelField label={"Remember me"} >
                            </SwitchLabelField>
                        </Grid>
                        <Grid item xs={12} md={12} lg={12} marginBottom={5}>
                            <ButtonField style={{fontWeight:"700",fontSize:"12px",fontFamily:"Lato, sans-serif",}}
                              variant={"contained"} name={"Login"} size={"large"} 
                              onClickHandler={onClickHandler}>
                            </ButtonField>
                        </Grid>
                        <Grid item xs={12} md={12} lg={12} >
                            <Link to="#" style={{fontSize:14,fontFamily:"Lato, sans-serif",
                              textDecoration:"none"}}>Forgot Password
                            </Link>
                        
                            <Typography style={{fontSize:14,fontFamily:"Lato, sans-serif"}}>
                              Don't have an account?<Link to={"/Pages/sign-up"} style={{fontSize:14,fontFamily:"Lato, sans-serif",
                              textDecoration:"none"}}>Sign Up!</Link>
                            </Typography>
                        </Grid>
                    </Grid>
                </Grid>
                <Grid xs={0} md={8} lg={8} item className="image-right-pannel">
                    <ImageField image={{src: loginPageImage}} >
                    </ImageField> 
                </Grid>
            </Grid>
           
        </div>
    )
}