import * as React from 'react';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Typography from '@mui/material/Typography';
import { Link } from 'react-router-dom';
import NavigateNextIcon from '@mui/icons-material/NavigateNext';
import { BottomNavigation, BottomNavigationAction } from '@mui/material';
import Box from '@mui/material/Box';
import SettingsIcon from '@mui/icons-material/Settings';

function handleClick(event) {
    event.preventDefault();
    console.info('You clicked a breadcrumb.');
  }
export default function BottomFooter(){
    return(
        <>
        <Box sx={{borderTop:'1px solid #e9e9e9',bottom: '0',width:1150,right:'0',position:'fixed',
         backgroundColor:'#fbfbfb'}}>
          <BottomNavigation>
            <Box sx={{display:'flex',flexGrow:'2',justifyContent:'flex-start',paddingTop:2}}>
               <Breadcrumbs  separator={<NavigateNextIcon fontSize="small" />} aria-label="breadcrumb">
                  <Link to='Pages/dashboard' key="1"  onClick={handleClick}
                   style={{textDecoration:'none',color: '#000',opacity:'.5',
                         fontSize:'14px',fontFamily:'Lato,sans-serif',marginLeft:20}}>
                     Dashboards   
                  </Link>
                  <Typography key="2" color="text.primary" style={{ fontSize:'14px',fontFamily:'Lato,sans-serif'}}>
                    Default
                  </Typography>
                </Breadcrumbs>
            </Box>
            <Box sx={{paddingTop:2,paddingRight:1}}>
              <Typography style={{fontSize:"14px",fontFamily:"Lato,sans-serif"}}>Version 1.4.0</Typography>
            </Box>
            <Box sx={{paddingTop:2}}>
              <Link to='/pages/footer-setting'>
                <SettingsIcon style={{color:'blue',marginRight:20}}/>
              </Link>
            </Box >
          </BottomNavigation>
        </Box>
        </>
    )
}