import * as React from 'react';
import {   Grid,  Typography } from "@mui/material"
import ImageField from "../../Components/ImageField/ImageField";
import LabelField from "../../Components/LabelField/LabelField";
import SwitchLabelField from "../../Components/SwitchLabelField/SwitchLabelField";
import TextFieldComponent from "../../Components/TextField/TextField";
import { Link } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import {  setEmailAddess, setName, setPassword1,  } from '../../Redux/Action/Actions';
import { useNavigate } from 'react-router-dom';
import ButtonFieldAdd from '../../Components/ButtonField/ButtionFieldAdd';



const signUpPageImage = require ('../../Images/page2.jpg');
const logoOfPage = require ('../../Images/logo.png');

export default function SignUp(){
    const dispatch = useDispatch();
    const user1=useSelector((state)=>state.feature.user1);
    const navigate=useNavigate();
    
    const onClickHandler=()=>{
        alert(JSON.stringify(user1));
        const options={
            method:'POST',
            headers:new Headers({"Content-type": "application/json"}),
            mode:'cors',
            body:JSON.stringify(user1),
        }
        fetch('https://fakestoreapi.com/users',options)
            .then(res=>res.json())
            .then(json=>{
                console.log(json);
                navigate("/Pages/dashboard");

            })
    };
    const onChangeName=(e)=>{
        dispatch(
            setName(e.target.value)
        )
    };
    const onChangeEmail=(e)=>{
        dispatch(
            setEmailAddess(e.target.value)
        )
    };
    const onChangePassword1=(e)=>{
        dispatch(
            setPassword1(e.target.value)
        )
    };
   

    return(
        <div>
            <Grid container spacing={2}>
                <Grid xs={12} md={4} lg={4} item>
                    <Grid container  spacing={2} padding={5}>
                        <Grid item xs={12} md={12} lg={12} >
                            <ImageField   image={{src:logoOfPage}}></ImageField> 
                        </Grid>
                        <Grid  xs={12} md={12} lg={12} item marginTop={10}>
                            <LabelField style={{fontWeight:"700",fontFamily:"Lato, sans-serif"}} variant={"h5"} label={"Sign-up"}/> 
                            <LabelField style={{fontWeight:"400",color:"#8f9091",fontSize:"14px",fontFamily:"Lato, sans-serif"}}variant={"p"} label={"Create your Account"}/>
                        
                        </Grid>
                        <Grid item xs={12} md={12} lg={12}>
                            <TextFieldComponent style={{display:"flex",flex:"1 1",
                              marginBottom:"20px",fontSize:"14px",fontFamily:"Lato, sans-serif",borderRadius:"20px",
                              backgroundColor:'rgba(235,235,235)',color: "#1f2022"}} 
                              size={"small"} placeholder={"Name"} onChange={onChangeName} 
                              value={user1.name} >
                            </TextFieldComponent>
                       
                            <TextFieldComponent  style={{display:"flex",flex:"1 1",  marginBottom:"20px",
                              fontSize:"14px",fontFamily:"Lato, sans-serif",borderRadius:"20px",color: "#1f2022",
                              backgroundColor:'rgba(235,235,235)'}}
                              placeholder={"Email address"} size={"small"} onChange={onChangeEmail}
                              value={user1.email} >
                            </TextFieldComponent> 
                        
                            <TextFieldComponent  style={{display:"flex",flex:"1 1",
                              fontSize:"14px",fontFamily:"Lato, sans-serif",borderRadius:"20px",color: "#1f2022",
                              backgroundColor: 'rgba(235,235,235)'}}
                              placeholder={"Password"} size={"small"} onChange={onChangePassword1}
                              value={user1.password} >
                            </TextFieldComponent> 
                        </Grid>
                        <Grid item xs={12} md={12} lg={12}>
                            <SwitchLabelField label={"I agree to the Terms and Privacy"} >
                            </SwitchLabelField>
                        </Grid>
                        <Grid item xs={12} md={12} lg={12} marginBottom={5}>
                            <ButtonFieldAdd style={{fontWeight:"700",fontSize:"12px",fontFamily:"Lato, sans-serif",}}
                              variant={"contained"} name={"Register"} size={"large"} 
                              onClickHandler={onClickHandler}>
                            </ButtonFieldAdd>
                        </Grid>
                        <Grid item xs={12} md={12} lg={12} >
                           <Typography style={{fontSize:14,fontFamily:"Lato, sans-serif"}}>
                              Have an account?<Link to={"/Pages/sign-in"} style={{fontSize:14,fontFamily:"Lato, sans-serif",
                              textDecoration:"none"}}>Sign In!</Link>
                            </Typography>
                        </Grid>
                    </Grid>
                </Grid>
                <Grid xs={0} md={8} lg={8} item className="image-right-pannel">
                    <ImageField image={{src: signUpPageImage}} >
                    </ImageField> 
                </Grid>
            </Grid>
           
        </div>
    )
}