import * as React from 'react';
import { styled } from '@mui/material/styles';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell, { tableCellClasses } from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import Paper from '@mui/material/Paper';
import { useState } from 'react';
import { useEffect } from 'react';
import { RouterTwoTone } from '@mui/icons-material';

const StyledTableCell = styled(TableCell)(({ theme }) => ({
  [`&.${tableCellClasses.head}`]: {
    backgroundColor:' rgba(31,32,34,.1)',
    color: 'black',
    fontWeight:700,
  },
  [`&.${tableCellClasses.body}`]: {
    fontSize: 14,
    backgroundColor: 'hsla(0,0%,92%,.3)',
  },
}));

const StyledTableRow = styled(TableRow)(({ theme }) => ({
  '&:nth-of-type': {
    backgroundColor: 'hsla(0,0%,92%,.3)',
  },

  '&:last-child td, &:last-child th': {
    border: 0,
  },
}));

function createData (
  billNo,
  patient, 
  doctor,
  billDate, 
  charges,
  tax,
  discount,
  total
 ) {
  return { billNo,patient,doctor,billDate,charges,tax,discount,total };
}

export default function PaymentTable() {
    const [appointment,setAppointment]=useState([]);

    useEffect(()=>{
        fetch("/json/Payment.json")
        .then(res=>res.json())
        .then(res=>{
            console.log(res);
            setAppointment(res)
        })
    },[])

  return (
    <TableContainer sx={{marginTop:5}}component={Paper}>
      <Table sx={{ minWidth: 700 }} aria-label="customized table">
        <TableHead>
          <TableRow>
            <StyledTableCell>Photo</StyledTableCell>
            <StyledTableCell align="left">Bill</StyledTableCell>
            <StyledTableCell align="left">Patient</StyledTableCell>
            <StyledTableCell align="left">Doctor</StyledTableCell>
            <StyledTableCell align="left">Date</StyledTableCell>
            <StyledTableCell align="left">Charges</StyledTableCell>
            <StyledTableCell align="left">Tax</StyledTableCell>
            <StyledTableCell align="left">Discount</StyledTableCell>
            <StyledTableCell align="left">Total</StyledTableCell>

          </TableRow>
        </TableHead>
        <TableBody>
          {appointment.map((row) => (
            <StyledTableRow key={row.name}>
              <StyledTableCell align="left">{row.billNo}</StyledTableCell>
              <StyledTableCell  align="left">{row.patient}</StyledTableCell>
              <StyledTableCell align="left">{row.doctor}</StyledTableCell>
              <StyledTableCell align="left">{row.billDate}</StyledTableCell>
              <StyledTableCell align="left">{row.charges}</StyledTableCell>
              <StyledTableCell align="left">{row.tax}</StyledTableCell>
              <StyledTableCell align="left">{row.discount}</StyledTableCell>
              <StyledTableCell align="left">{row.total}</StyledTableCell>
            </StyledTableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
}