import * as React from 'react';
import { styled } from '@mui/material/styles';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell, { tableCellClasses } from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import Paper from '@mui/material/Paper';
import { useState } from 'react';
import { useEffect } from 'react';
import ModeEditOutlinedIcon from '@mui/icons-material/ModeEditOutlined';
import { IconButton, Box,Typography } from '@mui/material';
import DeleteForeverOutlinedIcon from '@mui/icons-material/DeleteForeverOutlined';
import LaunchIcon from '@mui/icons-material/Launch';

const StyledTableCell = styled(TableCell)(({ theme }) => ({
  [`&.${tableCellClasses.head}`]: {
    backgroundColor:' #336cfb',
    color: 'white',
    fontWeight:700,
  },
  [`&.${tableCellClasses.body}`]: {
    fontSize: 14,
    backgroundColor: 'hsla(0,0%,92%,.3)',
  },
}));

const StyledTableRow = styled(TableRow)(({ theme }) => ({
  '&:nth-of-type': {
    backgroundColor: 'hsla(0,0%,92%,.3)',
  },

  '&:last-child td, &:last-child th': {
    border: 0,
  },
}));

function createData (
  img,
  name, 
  id,
  age,
  address, 
  number,
  lastVisit,
  status,
  
 ) {
  return { img, name, id,age,address,number,lastVisit,status };
}


export default function PatientsTable() {
    const [appointment,setAppointment]=useState([]);
    

    useEffect(()=>{
        fetch("/json/Patients.json")
        .then(res=>res.json())
        .then(res=>{
            console.log(res);
            setAppointment(res)
        })
    },[])

  return (
    <TableContainer sx={{marginTop:5}}component={Paper}>
      <Table sx={{ minWidth: 700 }} aria-label="customized table">
        <TableHead>
          <TableRow>
            <StyledTableCell>Photo</StyledTableCell>
            <StyledTableCell align="left">Name</StyledTableCell>
            <StyledTableCell align="left">Id</StyledTableCell>
            <StyledTableCell align="left">Age</StyledTableCell>
            <StyledTableCell align="left">Address</StyledTableCell>
            <StyledTableCell align="left">Number</StyledTableCell>
            <StyledTableCell align="left">Last Visit</StyledTableCell>
            <StyledTableCell align="left">Status</StyledTableCell>
            <StyledTableCell align="left">Actions</StyledTableCell>

          </TableRow>
        </TableHead>
        <TableBody>
          {appointment.map((row) => (
            <StyledTableRow key={row.name}>
              <StyledTableCell component="th" scope="row">
                <img src={row.img} style={{borderRadius:'50%'}}/>
              </StyledTableCell>
              <StyledTableCell align="left">{row.name}</StyledTableCell>
              <StyledTableCell style={{color:" rgb(165, 165, 165)"}} align="left">{row.id}</StyledTableCell>
              <StyledTableCell style={{color:" rgb(165, 165, 165)"}} align="left">{row.age}</StyledTableCell>
              <StyledTableCell style={{minWidth:200}} align="left">{row.address}</StyledTableCell>
              <StyledTableCell style={{color:"blue"}} align="left">{row.number}</StyledTableCell>
              <StyledTableCell style={{color:" rgb(165, 165, 165)"}} align="left">{row.lastVisit}</StyledTableCell>
              <StyledTableCell align="left">{row.status}</StyledTableCell>
              <StyledTableCell align="left">
                <Box sx={{display:'flex',alignItems:'flex-start',flexWrap:'nowrap'}}>
                <IconButton sx={{color:'white',borderRadius:'50%',backgroundColor:'black',margin:'3px'}}><LaunchIcon/></IconButton>
                <IconButton sx={{color:'white',borderRadius:'50%',backgroundColor:'blue',margin:'3px'}}><ModeEditOutlinedIcon/></IconButton>
                <IconButton sx={{color:'white',borderRadius:'50%',backgroundColor:'#ed5564',margin:'3px'}}><DeleteForeverOutlinedIcon/></IconButton>
                </Box>
              </StyledTableCell>
            </StyledTableRow>
            
          ))}
        </TableBody>
      </Table>
     
    </TableContainer>
  );
}