
import {   OutlinedInput, TextField, Typography } from "@mui/material";
import * as React from "react";



export default function TextFieldComponent(props){
    return(
        <div>
        
            <OutlinedInput style={props.style} placeholder={props.placeholder} size={props.size} 
              onChange={props.onChange} value={props.value} onClick={props.onClick} />
            {
                props.error&&
                <Typography component={"span"}>

                    {props.error}
                </Typography>
            }
        </div>
    )
}